/**
 * @summary Get attack incident history
 */
export const getGetIncidentsUrl = (params?: GetIncidentsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/incidents?${stringifiedParams}`
    : `/api/incidents`;
};

export const getIncidents = async (
  params?: GetIncidentsParams,
  options?: RequestInit,
): Promise<Incident[]> => {
  return customFetch<Incident[]>(getGetIncidentsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetIncidentsQueryKey = (params?: GetIncidentsParams) => {
  return [`/api/incidents`, ...(params ? [params] : [])] as const;
};

export const getGetIncidentsQueryOptions = <
  TData = Awaited<ReturnType<typeof getIncidents>>,
  TError = ErrorType<unknown>,
>(
  params?: GetIncidentsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getIncidents>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetIncidentsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getIncidents>>> = ({
    signal,
  }) => getIncidents(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getIncidents>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetIncidentsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getIncidents>>
>;
export type GetIncidentsQueryError = ErrorType<unknown>;

